1	import { z } from "zod";
2	
3	const CATEGORIES = ["skills", "mcp", "slash", "plugins"] as const;
4	const SCOPES = ["personal", "org", "enterprise"] as const;
5	const FUNC_CATS = ["workTask", "business", "tools"] as const;
6	const FILTER_CHIPS = ["all", "trending", "new", "official", "free"] as const;
7	const SORTS = ["downloads", "stars", "recent"] as const;
8	const TAG_MATCHES = ["any", "all"] as const;
9	
10	export const PAGE_SIZE = 24;
11	
12	export const filtersSchema = z.object({
13	  q: z.string().trim().min(1).max(120).optional(),
14	  category: z.enum(CATEGORIES).optional(),
15	  scope: z.enum(SCOPES).optional(),
16	  funcCat: z.enum(FUNC_CATS).optional(),
17	  subCat: z.string().trim().min(1).max(40).optional(),
18	  l2: z.string().trim().min(1).max(40).optional(),
19	  // Department id (dotted-path) or the literal "__all" to disable the filter.
20	  dept: z.string().trim().min(1).max(120).optional(),
21	  tags: z.array(z.string().trim().min(1).max(40)).max(16).optional(),
22	  tagMatch: z.enum(TAG_MATCHES).optional(),
23	  filter: z.enum(FILTER_CHIPS).optional(),
24	  sort: z.enum(SORTS).optional(),
25	  page: z.coerce.number().int().min(1).max(1000).optional(),
26	});
27	
28	export type Filters = z.infer<typeof filtersSchema>;
29	
30	/**
31	 * Parse Next.js searchParams into typed Filters. Invalid input is dropped,
32	 * so a malformed URL silently falls back to "no filter" rather than 500ing.
33	 */
34	export function parseFilters(
35	  input: Record<string, string | string[] | undefined>,
36	): Filters {
37	  const tags = input.tags;
38	  const normalized = {
39	    ...input,
40	    tags:
41	      tags === undefined
42	        ? undefined
43	        : Array.isArray(tags)
44	          ? tags
45	          : tags.split(",").filter(Boolean),
46	  };
47	  const parsed = filtersSchema.safeParse(normalized);
48	  return parsed.success ? parsed.data : {};
49	}
50	
51	export function pageOffset(page: number | undefined) {
52	  return ((page ?? 1) - 1) * PAGE_SIZE;
53	}
54	
55	/**
56	 * Adapter from `URLSearchParams` (the runtime shape) to the `Record` shape
57	 * `parseFilters` consumes. Repeated keys (`?tags=a&tags=b`) accumulate into
58	 * an array; `serializeFilters` always emits comma-joined, but external
59	 * links may use the array form and the validator already handles both.
60	 */
61	export function searchParamsToInput(
62	  searchParams: URLSearchParams,
63	): Record<string, string | string[]> {
64	  const out: Record<string, string | string[]> = {};
65	  for (const [key, value] of searchParams.entries()) {
66	    const prev = out[key];
67	    if (prev === undefined) {
68	      out[key] = value;
69	    } else if (Array.isArray(prev)) {
70	      prev.push(value);
71	    } else {
72	      out[key] = [prev, value];
73	    }
74	  }
75	  return out;
76	}
77	
